import os
import io
import time
import threading
import requests
from flask import Flask, request, send_file, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mkv'}

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join(app.config['UPLOAD_FOLDER'], filename))
        return jsonify({'message': 'File uploaded successfully'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/video/<path:filename>', methods=['GET'])
def stream_video(filename):
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if not os.path.exists(file_path):
        return jsonify({'error': 'File not found'}), 404

    file_size = os.path.getsize(file_path)
    range_header = request.headers.get('Range', None)

    if range_header:
        range_values = range_header.split('=')[1].split('-')
        start = int(range_values[0])
        end = int(range_values[1]) if range_values[1] else file_size - 1
        block_size = end - start + 1
    else:
        start = 0
        end = file_size - 1
        block_size = file_size

    with open(file_path, 'rb') as file:
        file.seek(start)
        video_data = file.read(block_size)

    response = send_file(
        io.BytesIO(video_data),
        mimetype='video/mp4',
        as_attachment=False,
        conditional=True,
        headers={
            'Content-Range': f'bytes {start}-{end}/{file_size}',
            'Accept-Ranges': 'bytes',
            'Content-Length': str(block_size)
        }
    )

    return response

@app.route('/video/<path:filename>/info', methods=['GET'])
def get_video_info(filename):
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if not os.path.exists(file_path):
        return jsonify({'error': 'File not found'}), 404

    file_size = os.path.getsize(file_path)
    return jsonify({'file_size': file_size})

if __name__ == '__main__':
    app.run(debug=True)

import os
import shutil
import threading
import time
import uuid
from collections import deque
from io import BytesIO

class VideoStreamingService:
    def __init__(self, video_directory, temp_directory, chunk_size=1024 * 1024):
        self.video_directory = video_directory
        self.temp_directory = temp_directory
        self.chunk_size = chunk_size
        self.active_streams = {}

    def upload_video(self, video_file, video_name):
        video_path = os.path.join(self.video_directory, video_name)
        shutil.copy(video_file, video_path)
        return video_name

    def start_stream(self, video_name, resolution, start_time=0, quality=100):
        stream_id = str(uuid.uuid4())
        self.active_streams[stream_id] = {
            "video_name": video_name,
            "resolution": resolution,
            "start_time": start_time,
            "quality": quality,
            "paused": False,
            "buffer": deque(),
            "buffer_lock": threading.Lock(),
            "stop_event": threading.Event()
        }
        threading.Thread(target=self.stream_video, args=(stream_id,)).start()
        return stream_id

    def stream_video(self, stream_id):
        stream = self.active_streams[stream_id]
        video_path = os.path.join(self.video_directory, stream["video_name"])
        with open(video_path, "rb") as f:
            f.seek(int(stream["start_time"] * 1000 * 1000 / 8))
            while not stream["stop_event"].is_set():
                with stream["buffer_lock"]:
                    if len(stream["buffer"]) < 5 and not stream["paused"]:
                        chunk = f.read(self.chunk_size)
                        if chunk:
                            stream["buffer"].append(chunk)
                        else:
                            stream["stop_event"].set()
                            break
                time.sleep(0.1)

    def pause_stream(self, stream_id):
        self.active_streams[stream_id]["paused"] = True

    def resume_stream(self, stream_id):
        self.active_streams[stream_id]["paused"] = False

    def seek_stream(self, stream_id, time_offset):
        stream = self.active_streams[stream_id]
        stream["start_time"] = time_offset
        stream["buffer"].clear()
        stream["stop_event"].set()
        self.start_stream(stream["video_name"], stream["resolution"], stream["start_time"], stream["quality"])

    def get_stream_chunk(self, stream_id):
        stream = self.active_streams[stream_id]
        with stream["buffer_lock"]:
            if stream["buffer"]:
                return stream["buffer"].popleft()
            else:
                return None

    def stop_stream(self, stream_id):
        self.active_streams[stream_id]["stop_event"].set()
        del self.active_streams[stream_id]

