        self.video_dir = video_dir
        self.chunk_size = chunk_size
        self.video_queue = queue.Queue()
        self.connection_quality = 1.0  # Assume good connection quality initially
        self.start_video_stream_thread()

    def start_video_stream_thread(self):
        thread = threading.Thread(target=self.video_stream_worker)
        thread.daemon = True
        thread.start()

    def video_stream_worker(self):
        while True:
            video_path, client_connection = self.video_queue.get()
            self.stream_video(video_path, client_connection)

    def stream_video(self, video_path, client_connection):
        try:
            video_size = os.path.getsize(video_path)
            start_time = time.time()
            with open(video_path, 'rb') as f:
                while True:
                    chunk = f.read(self.chunk_size)
                    if not chunk:
                        break
                    client_connection.send(chunk)
                    time.sleep(self.chunk_size / (video_size * self.connection_quality))
            end_time = time.time()
            print(f"Video streamed in {end_time - start_time:.2f} seconds.")
        except Exception as e:
            print(f"Error streaming video: {e}")

    def handle_client_request(self, client_connection, video_name):
        video_path = os.path.join(self.video_dir, video_name)
        if os.path.exists(video_path):
            self.video_queue.put((video_path, client_connection))
        else:
            client_connection.send(b"Video not found.")

    def update_connection_quality(self, quality):
        self.connection_quality = quality

