# Video queue for concurrent requests
video_queue = queue.Queue()

# Video streaming function
def stream_video(video_path, start_time=0, bitrate=None):
    try:
        file_size = os.path.getsize(video_path)
        headers = {'Content-Type': 'video/mp4', 'Content-Length': str(file_size)}

        def generate():
            with open(video_path, 'rb') as f:
                f.seek(int(start_time * 1024 * 1024))
                while True:
                    chunk = f.read(1024 * 1024)
                    if not chunk:
                        break
                    yield chunk

        return app.response_class(generate(), headers=headers)
    except Exception as e:
        print(f'Error streaming video: {e}')
        return 'Error streaming video', 500

