from flask import Flask, request, send_file, jsonify
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy import Column, Integer, String, DateTime
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///videos.db'
db = SQLAlchemy(app)

class Video(db.Model):
    id = Column(Integer, primary_key=True)
    title = Column(String(100), nullable=False)
    file_path = Column(String(200), nullable=False)
    created_at = Column(DateTime, default=datetime.datetime.utcnow)

    def __repr__(self):
        return f'Video(id={self.id}, title="{self.title}")'

@app.route('/videos', methods=['GET'])
def list_videos():
    videos = Video.query.all()
    return jsonify([{'id': v.id, 'title': v.title, 'created_at': v.created_at.isoformat()} for v in videos])

@app.route('/videos/<int:video_id>', methods=['GET'])
def get_video(video_id):
    video = Video.query.get_or_404(video_id)
    return send_file(video.file_path, download_name=f'{video.title}.mp4')

@app.route('/videos', methods=['POST'])
def upload_video():
    file = request.files['video']
    filename = secure_filename(file.filename)
    file_path = os.path.join('uploads', filename)
    file.save(file_path)

    video = Video(title=file.filename, file_path=file_path)
    db.session.add(video)
    db.session.commit()

    return jsonify({'id': video.id, 'title': video.title, 'created_at': video.created_at.isoformat()})

@app.route('/videos/<int:video_id>/transcode', methods=['POST'])
def transcode_video(video_id):
    video = Video.query.get_or_404(video_id)
    resolutions = request.get_json()['resolutions']

    for resolution in resolutions:
        output_file = os.path.splitext(video.file_path)[0] + f'_{resolution}.mp4'
        stream = ffmpeg.input(video.file_path)
        stream = ffmpeg.filter(stream, 'scale', resolution, force_original_aspect_ratio=1, pad=resolution)
        stream = ffmpeg.output(stream, output_file)
        ffmpeg.run(stream)

    return jsonify({'message': 'Transcoding completed'})

